import PagoFastCashStatic from "./static";
import { headers } from "next/headers";
import { redirect } from "next/navigation";

export default async function Page({
  params,
}: {
  params: Promise<{ token: string }>;
}) {
  const { token } = await params;

  if (!token) {
    redirect("/");
  }

  const h = await headers();
  const host = h.get("host");

  if (!host) {
    redirect("/");
  }

  const protocol = host.includes("localhost") ? "http" : "https";
  const baseUrl = `${protocol}://${host}`;

  let tipoPlantilla = "1";

  try {
    // 1) SOLO consultar la plantilla
    const res = await fetch(
      `${baseUrl}/api/plantillas-temporales-3/${token}`,
      {
        cache: "no-store",
      }
    );

    if (!res.ok) {
      throw new Error(`Error consultando plantilla: ${res.status}`);
    }

    const json = await res.json().catch(() => null);
    const data = json?.data ?? json;

    if (!data) {
      throw new Error("No se pudo obtener la plantilla");
    }

    tipoPlantilla = data?.tipo_plantilla || "1";

    // 2) Verificar pagado
    if (data?.pagado === true) {
      redirect("/gracias");
    }
  } catch (e) {
    console.error("Error verificando pago:", e);
  }

  // 3) Si no está pagado, mostrar página normal
  return <PagoFastCashStatic token={token} tipoPlantilla={tipoPlantilla} />;
}